import{_ as s,c as i,o as a,ae as t}from"./chunks/framework.BHrE6nLq.js";const k=JSON.parse('{"title":"Mounting a LUKS-Encrypted QCOW2 Image","description":"","frontmatter":{},"headers":[],"relativePath":"docs/how_to/libvirt/mount-luks-images.md","filePath":"docs/how_to/libvirt/mount-luks-images.md"}'),n={name:"docs/how_to/libvirt/mount-luks-images.md"};function o(p,e,h,l,d,c){return a(),i("div",null,e[0]||(e[0]=[t(`<h1 id="mounting-a-luks-encrypted-qcow2-image" tabindex="-1">Mounting a LUKS-Encrypted QCOW2 Image <a class="header-anchor" href="#mounting-a-luks-encrypted-qcow2-image" aria-label="Permalink to &quot;Mounting a LUKS-Encrypted QCOW2 Image&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>LUKS (Linux Unified Key Setup) encryption secures QCOW2 images used in virtualization platforms like Libvirt/KVM. Mounting such an encrypted image allows you to access its contents on a Linux system. This guide walks you through creating an encrypted QCOW2 image, converting an existing image to encrypted format, and mounting it using <code>qemu-nbd</code> on a Linux OS.</p><h2 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h2><ul><li><strong>Operating System</strong>: Linux (e.g., Fedora, Ubuntu, CentOS, or Rocky Linux).</li><li><strong>Virtualization</strong>: Libvirt/KVM.</li><li><strong>Image Format</strong>: QCOW2 with LUKS encryption.</li><li><strong>Tools</strong>: <code>qemu-img</code>, <code>qemu-nbd</code> (part of <code>qemu-utils</code> or <code>qemu-kvm</code> packages).</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="step-1-create-an-empty-encrypted-qcow2-image" tabindex="-1">Step 1 - Create an Empty Encrypted QCOW2 Image <a class="header-anchor" href="#step-1-create-an-empty-encrypted-qcow2-image" aria-label="Permalink to &quot;Step 1 - Create an Empty Encrypted QCOW2 Image&quot;">​</a></h3><p>First, create a new, empty QCOW2 image with LUKS encryption. You’ll need to specify a password and size. Ensure <code>qemu-utils</code> is installed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-utils</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For Debian/Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For RHEL/CentOS/Rocky</span></span></code></pre></div><p>Run the following command, replacing <code>password-bebas</code> with your chosen password and <code>ukuran-bebas</code> with your desired size:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=password-bebas,format=raw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> encrypt.format=luks,encrypt.key-secret=sec0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nama-image.qcow2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ukuran-bebas</span></span></code></pre></div><p><strong>Example</strong>: Create a 30GB image with the password <code>geheim247</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=geheim247,format=raw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> encrypt.format=luks,encrypt.key-secret=sec0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.qcow2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 30G</span></span></code></pre></div><ul><li><code>--object secret,id=sec0,data=geheim247,format=raw</code>: Defines the password (<code>geheim247</code>).</li><li><code>-f qcow2</code>: Specifies the QCOW2 format.</li><li><code>-o encrypt.format=luks,encrypt.key-secret=sec0</code>: Enables LUKS encryption with the secret.</li><li><code>demo.qcow2 30G</code>: Sets the output file name and size (30 gigabytes).</li></ul><p>This creates an empty encrypted image ready for use.</p><h3 id="step-2-convert-an-existing-qcow2-image-to-encrypted-format" tabindex="-1">Step 2 - Convert an Existing QCOW2 Image to Encrypted Format <a class="header-anchor" href="#step-2-convert-an-existing-qcow2-image-to-encrypted-format" aria-label="Permalink to &quot;Step 2 - Convert an Existing QCOW2 Image to Encrypted Format&quot;">​</a></h3><p>If you have an unencrypted QCOW2 image (e.g., <code>centos7.qcow2</code>), convert its contents into the encrypted image created in Step 1. Use the <code>qemu-img convert</code> command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=password-bebas</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,file.filename=nama-image-sebelum-encrypt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target-image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,encrypt.key-secret=sec0,file.filename=nama-image-yg-telah-dibuat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p><strong>Example</strong>: Convert <code>centos7.qcow2</code> to <code>demo.qcow2</code> with the password <code>geheim247</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=geheim247</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,file.filename=centos7.qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target-image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,encrypt.key-secret=sec0,file.filename=demo.qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><ul><li><code>--image-opts driver=qcow2,file.filename=centos7.qcow2</code>: Specifies the source (unencrypted) image.</li><li><code>--target-image-opts driver=qcow2,encrypt.key-secret=sec0,file.filename=demo.qcow2</code>: Defines the encrypted target image.</li><li><code>-n</code>: Skips pre-allocation for speed.</li><li><code>-p</code>: Shows conversion progress.</li></ul><p>Wait for the process to complete. The encrypted image (<code>demo.qcow2</code>) now contains the data from the original image.</p><h3 id="step-3-connect-the-luks-image-to-a-block-device" tabindex="-1">Step 3 - Connect the LUKS Image to a Block Device <a class="header-anchor" href="#step-3-connect-the-luks-image-to-a-block-device" aria-label="Permalink to &quot;Step 3 - Connect the LUKS Image to a Block Device&quot;">​</a></h3><p>Use <code>qemu-nbd</code> to map the encrypted QCOW2 image to a network block device (NBD) on your Linux system. This makes it accessible as a disk. Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-nbd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=geheim247,format=raw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,file.filename=demo.qcow2,encrypt.format=luks,encrypt.key-secret=sec0</span></span></code></pre></div><ul><li><code>--object secret,id=sec0,data=geheim247,format=raw</code>: Provides the password.</li><li><code>-c /dev/nbd1</code>: Connects the image to <code>/dev/nbd1</code> (use <code>nbd0</code>, <code>nbd1</code>, etc., depending on availability).</li><li><code>--image-opts</code>: Specifies the encrypted image details.</li></ul><p>Ensure the <code>nbd</code> kernel module is loaded:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nbd</span></span></code></pre></div><h3 id="step-4-verify-the-connection" tabindex="-1">Step 4 - Verify the Connection <a class="header-anchor" href="#step-4-verify-the-connection" aria-label="Permalink to &quot;Step 4 - Verify the Connection&quot;">​</a></h3><p>Check if the image is connected as a block device:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Device      Boot Start      End  Sectors Size Id Type</span></span>
<span class="line"><span>/dev/nbd1p1 *     2048 62914526 62912479  30G 83 Linux</span></span></code></pre></div><p>This shows the partitions within the image (e.g., <code>/dev/nbd1p1</code>). If no output appears, ensure the NBD connection succeeded.</p><h3 id="step-5-mount-the-luks-image" tabindex="-1">Step 5 - Mount the LUKS Image <a class="header-anchor" href="#step-5-mount-the-luks-image" aria-label="Permalink to &quot;Step 5 - Mount the LUKS Image&quot;">​</a></h3><p>Mount the partition to a directory (e.g., <code>/mnt</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd1p1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span></code></pre></div><p>Verify the mount:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -kh</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Filesystem      Size  Used Avail Use% Mounted on</span></span>
<span class="line"><span>/dev/nbd1p1      30G  1.2G   29G   4% /mnt</span></span></code></pre></div><p>You can now access the filesystem contents in <code>/mnt</code>.</p><h4 id="disconnect-the-image" tabindex="-1">Disconnect the Image <a class="header-anchor" href="#disconnect-the-image" aria-label="Permalink to &quot;Disconnect the Image&quot;">​</a></h4><p>When done, unmount and disconnect the image:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-nbd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --disconnect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nbd1</span></span></code></pre></div><p>This safely detaches the image from the NBD device.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>If the image has multiple partitions, repeat the mount process for each (e.g., <code>/dev/nbd1p2</code>).</li><li>Ensure the mount point (e.g., <code>/mnt</code>) exists (<code>sudo mkdir /mnt</code> if needed).</li><li>The password must match the one used during encryption, or the image won’t open.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://lists.gnu.org/archive/html/qemu-devel/2017-07/msg06731.html" target="_blank" rel="noreferrer">QEMU Devel Mailing List: LUKS Encryption</a></li><li><a href="https://cloud.ibm.com/docs/vpc?topic=vpc-create-encrypted-custom-image" target="_blank" rel="noreferrer">IBM Cloud: Creating Encrypted Custom Images</a></li></ul>`,50)]))}const g=s(n,[["render",o]]);export{k as __pageData,g as default};
